\begin{lemma}[Affine commutative squares are pushouts of rings]
  \label{lem:commRingCat_isPushout_iff_mathlib}
  \lean{CommRingCat.isPushout_iff_isPushout}
  \mathlibok
  \textit{Provided by Mathlib.}
  A commutative square of commutative rings \(R \to A\), \(R \to R'\), \(A \to T\),
  \(R' \to T\) is a pushout (cocartesian) square in the category of commutative rings if and
  only if it is an algebra pushout in the sense of \(\operatorname{Algebra.IsPushout}\) ---
  equivalently, the corner ring is the tensor product \(T = A \otimes_R R'\) of the two legs
  over the base \(R\). Applying \(\operatorname{Spec}\) carries such a cocartesian ring square
  to a cartesian square of affine schemes, and conversely.
\end{lemma}

